def get_hip_version():
    hipconfig = shutil.which("hipconfig")
    if hipconfig is None:
        hipconfig = os.path.join(os.environ.get("ROCM_PATH", "/opt/rocm"), "bin", "hipconfig")
    version = subprocess.run(
        f"{hipconfig} --version", shell=True, capture_output=True, text=True
    )
    return parse(version.stdout.split()[-1].rstrip("-").replace("-", "+"))

def _get_default_gpu_arch():
    amdgpu_arch = shutil.which("amdgpu-arch")
    if amdgpu_arch is None:
        amdgpu_arch = os.path.join(os.environ.get("ROCM_PATH", "/opt/rocm"), "bin", "amdgpu-arch")
    if not os.path.exists(amdgpu_arch):
        # fallback to typical pip wheel layout
        for root in ["_rocm_sdk_devel", "_rocm_sdk_core"]:
            candidate = os.path.join(os.path.dirname(sys.executable), "lib", "python3.13", "site-packages", root, "bin", "amdgpu-arch")
            if os.path.exists(candidate):
                amdgpu_arch = candidate
                break
    return (
        subprocess.run(
            f"{amdgpu_arch}", shell=True, capture_output=True, text=True
        )
        .stdout.strip()
        .split("\n")[0]
    )

DEFAULT_GPU_ARCH = _get_default_gpu_arch()
